mapper.select:
select concat('aircraft:', a.aircraft_id) as id, null as parent_id, a.aircraft_name as name, 'aircraft' as node_type, 1 as level
from aircraft a where concat('aircraft:', a.aircraft_id) = #{node_id}
union all
select concat('aircraft:', a.aircraft_id) as id, null as parent_id, a.aircraft_name as name, 'aircraft' as node_type, 1 as level
from subsystems s inner join aircraft a on a.aircraft_id = s.aircraft_id where concat('subsystem:', s.subsystem_id) = #{node_id}
union all
select concat('subsystem:', s.subsystem_id) as id, concat('aircraft:', s.aircraft_id) as parent_id, s.subsystem_name as name, 'subsystem' as node_type, 2 as level
from subsystems s where concat('subsystem:', s.subsystem_id) = #{node_id}
union all
select concat('aircraft:', a.aircraft_id) as id, null as parent_id, a.aircraft_name as name, 'aircraft' as node_type, 1 as level
from equipments e inner join subsystems s on s.subsystem_id = e.subsystem_id inner join aircraft a on a.aircraft_id = s.aircraft_id where concat('equipment:', e.equipment_id) = #{node_id}
union all
select concat('subsystem:', s.subsystem_id) as id, concat('aircraft:', s.aircraft_id) as parent_id, s.subsystem_name as name, 'subsystem' as node_type, 2 as level
from equipments e inner join subsystems s on s.subsystem_id = e.subsystem_id where concat('equipment:', e.equipment_id) = #{node_id}
union all
select concat('equipment:', e.equipment_id) as id, concat('subsystem:', e.subsystem_id) as parent_id, e.equipment_name as name, 'equipment' as node_type, 3 as level
from equipments e where concat('equipment:', e.equipment_id) = #{node_id}
union all
select concat('aircraft:', a.aircraft_id) as id, null as parent_id, a.aircraft_name as name, 'aircraft' as node_type, 1 as level
from components c inner join equipments e on e.equipment_id = c.equipment_id inner join subsystems s on s.subsystem_id = e.subsystem_id inner join aircraft a on a.aircraft_id = s.aircraft_id where concat('component:', c.component_id) = #{node_id}
union all
select concat('subsystem:', s.subsystem_id) as id, concat('aircraft:', s.aircraft_id) as parent_id, s.subsystem_name as name, 'subsystem' as node_type, 2 as level
from components c inner join equipments e on e.equipment_id = c.equipment_id inner join subsystems s on s.subsystem_id = e.subsystem_id where concat('component:', c.component_id) = #{node_id}
union all
select concat('equipment:', e.equipment_id) as id, concat('subsystem:', e.subsystem_id) as parent_id, e.equipment_name as name, 'equipment' as node_type, 3 as level
from components c inner join equipments e on e.equipment_id = c.equipment_id where concat('component:', c.component_id) = #{node_id}
union all
select concat('component:', c.component_id) as id, concat('equipment:', c.equipment_id) as parent_id, c.component_name as name, 'component' as node_type, 4 as level
from components c where concat('component:', c.component_id) = #{node_id}
union all
select concat('aircraft:', a.aircraft_id) as id, null as parent_id, a.aircraft_name as name, 'aircraft' as node_type, 1 as level
from part_templates pt inner join components c on c.component_id = pt.component_id inner join equipments e on e.equipment_id = c.equipment_id inner join subsystems s on s.subsystem_id = e.subsystem_id inner join aircraft a on a.aircraft_id = s.aircraft_id where concat('part_template:', pt.part_template_id) = #{node_id}
union all
select concat('subsystem:', s.subsystem_id) as id, concat('aircraft:', s.aircraft_id) as parent_id,
s.subsystem_name as name, 'subsystem' as node_type, 2 as level
from part_templates pt inner join components c on c.component_id = pt.component_id inner join equipments e on e.equipment_id = c.equipment_id inner join subsystems s on s.subsystem_id = e.subsystem_id where concat('part_template:', pt.part_template_id) = #{node_id}
union all
select concat('equipment:', e.equipment_id) as id, concat('subsystem:', e.subsystem_id) as parent_id,
e.equipment_name as name, 'equipment' as node_type, 3 as level
from part_templates pt inner join components c on c.component_id = pt.component_id inner join equipments e on e.equipment_id = c.equipment_id where concat('part_template:', pt.part_template_id) = #{node_id}
union all
select concat('component:', c.component_id) as id, concat('equipment:', c.equipment_id) as parent_id, c.component_name as name, 'component' as node_type, 4 as level
from part_templates pt inner join components c on c.component_id = pt.component_id where concat('part_template:', pt.part_template_id) = #{node_id}
union all
select concat('part_template:', pt.part_template_id) as id,
concat('component:', pt.component_id) as parent_id, pt.part_name as name, 'part_template' as node_type, 5 as level
from part_templates pt where concat('part_template:', pt.part_template_id) = #{node_id}
order by level

select count(1) from part_instances pi inner join part_templates pt on pt.part_template_id = pi.part_template_id where 1 = 1
and concat('component:', pt.component_id) = #{node_id}
and concat('part_template:', pt.part_template_id) = #{node_id}
and 1 = 0

select pi.part_instance_id as part_id, pi.part_instance_id as part_instance_id, pt.part_template_id as part_template_id, pt.part_number as part_code, pt.part_name as part_name, pt.material as material, pt.specification as spec_model, pi.batch_number as batch_no, pi.batch_number as batch_number, pi.serial_number as serial_number, pi.manufacturer as manufacturer, pi.production_date as production_date, pi.current_status as status, pi.current_status as current_status, pi.quality_level as quality_level, pi.key_degree as key_degree from part_instances pi inner join part_templates pt on pt.part_template_id = pi.part_template_id where 1 = 1
and concat('component:', pt.component_id) = #{module_id}
and concat('part_template:', pt.part_template_id) = #{module_id}
and 1 = 0
and ( pt.part_number like concat('%', #{keyword}, '%') or pt.part_name like concat('%', #{keyword}, '%') or pt.specification like concat('%', #{keyword}, '%') or pi.serial_number like concat('%', #{keyword}, '%') )
and pt.material = #{material}
and pi.current_status = #{status}
order by pi.create_time desc limit #{page_size} offset #{offset}

